import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class NativeEvaluationStatisticsEstimateTest {

	@TempDir
	File dataDir;

	@Test
	void usesSynopsisBackedEnvelopeForBoundPatterns() throws Exception {
		SailRepository repository = new SailRepository(new NativeStore(dataDir, "spoc,posc"));
		try {
			loadData(repository);
			EvaluationStatistics statistics = extractEvaluationStatistics(repository);
			StatementPattern unbound = statementPattern("SELECT * WHERE { ?s ?p ?o . }");
			StatementPattern follows = statementPattern("SELECT * WHERE { ?s <urn:test:follows> ?o . }");

			EvaluationStatistics.CardinalityEstimate unboundEstimate = statistics.getCardinalityEstimate(unbound);
			EvaluationStatistics.CardinalityEstimate followsEstimate = statistics.getCardinalityEstimate(follows);

			assertEquals("native-range-count-synopsis", followsEstimate.source);
			assertTrue(followsEstimate.lowerBound <= followsEstimate.estimate);
			assertTrue(followsEstimate.estimate <= followsEstimate.upperBound);
			assertTrue(followsEstimate.confidence > unboundEstimate.confidence);
			assertTrue(followsEstimate.upperBound <= unboundEstimate.upperBound);
		} finally {
			repository.shutDown();
		}
	}

	private static void loadData(SailRepository repository) {
		SimpleValueFactory vf = SimpleValueFactory.getInstance();
		IRI follows = vf.createIRI("urn:test:follows");
		IRI name = vf.createIRI("urn:test:name");
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			for (int i = 0; i < 12; i++) {
				IRI subject = vf.createIRI("urn:test:user:" + i);
				IRI object = vf.createIRI("urn:test:user:" + ((i + 1) % 12));
				connection.add(subject, follows, object);
				connection.add(subject, name, vf.createLiteral("u" + i));
			}
			connection.commit();
		}
	}

	private static EvaluationStatistics extractEvaluationStatistics(SailRepository repository) throws Exception {
		Object sail = repository.getSail();
		Method getSailStoreMethod = sail.getClass().getDeclaredMethod("getSailStore");
		getSailStoreMethod.setAccessible(true);
		SailStore sailStore = (SailStore) getSailStoreMethod.invoke(sail);
		return sailStore.getEvaluationStatistics();
	}

	private static StatementPattern statementPattern(String query) {
		ParsedTupleQuery parsed = QueryParserUtil.parseTupleQuery(QueryLanguage.SPARQL, query, null);
		List<StatementPattern> patterns = StatementPatternCollector.process(parsed.getTupleExpr());
		return patterns.get(0);
	}
}
